script:
frappe.ui.form.on('Employee', {
    refresh(frm){
        sumWeekdays(frm);
    },
	custom_monday: function(frm) {
	    sumWeekdays(frm);
	},
	custom_tuesday: function(frm) {
	    sumWeekdays(frm);
	},
	custom_wednesday: function(frm) {
	    sumWeekdays(frm);
	},
	custom_thursday: function(frm) {
	    sumWeekdays(frm);
	},
	custom_friday: function(frm) {
	    sumWeekdays(frm);
	}
})


function sumWeekdays(frm) {
    const sum = frm.doc.custom_monday + frm.doc.custom_tuesday + frm.doc.custom_wednesday + frm.doc.custom_thursday + frm.doc.custom_friday;
    frm.set_value("custom_weekly_sum",sum);
}

frappe.ui.form.on("Leave Application", {
    refresh(frm) {
        if(frm.doc.custom_fractional_day_value) {
            frm.trigger("set_fractional_day_warning");
        } 
        else {
			frm.set_df_property("custom_fractional_leave_warning", "options", `<div> </div>`);
        }   
	},
	set_fractional_day_warning: function (frm) {
		const d = new Date(frm.doc.custom_last_workday_date);
		const formattedDate = d.toLocaleDateString("de-DE");
	    var html = `
                                <div class="alert alert-warning" style="margin-top:10px; font-size: 20px; padding: 15px; font-weight: bold;">
                                    <strong>Fractional Day in Leave:</strong><br>
                                    You are applying for a total of ${frm.doc.total_leave_days} days of vacation. Note that on ${frm.doc.custom_last_workday_weekday} ${formattedDate} you have a <strong> partial day of vacation where you have to work ${frm.doc.custom_hours_to_work} hours and ${frm.doc.custom_minutes_to_work} minutes. </strong>
                                </div>
                            `;

		frm.set_df_property("custom_fractional_leave_warning", "options", html);
	},
	calculate_total_days: function (frm) {
		if (frm.doc.from_date && frm.doc.to_date && frm.doc.employee && frm.doc.leave_type) {
			return frappe.call({
				method: "workplan.workplan.overrides.leave_application.get_number_of_leave_days_leave_application",
				args: {
					employee: frm.doc.employee,
					leave_type: frm.doc.leave_type,
					from_date: frm.doc.from_date,
					to_date: frm.doc.to_date,
					half_day: frm.doc.half_day,
					half_day_date: frm.doc.half_day_date,
				},
				callback: function (r) {
					if (r && r.message) {
						frm.set_value("custom_fractional_day_value", r.message.fractional_value);
						if (r.message.fractional_value) {
							frm.set_value("total_leave_days", r.message.total_leave_days);

							let weekday = "";
							switch (r.message.weekday) {
								case 0:
									weekday = "Monday";
									break;
								case 1:
									weekday = "Tuesday";
									break;
								case 2:
									weekday = "Wednesday";
									break;
								case 3:
									weekday = "Thursday";
									break;
								case 4:
									weekday = "Friday";
									break;
								default:
									weekday = "Unknown Weekday";
							}

							frm.set_value("custom_last_workday_date", r.message.date);
							frm.set_value("custom_last_workday_weekday", weekday);

							const total_hours = r.message.fractional_work * 8;
							const hours = Math.floor(total_hours);
							const minutes = Math.floor((total_hours - hours) * 60);

							frm.set_value("custom_hours_to_work", hours);
							frm.set_value("custom_minutes_to_work", minutes);

							frm.trigger("set_fractional_day_warning");const d = new Date(r.message.date);
						} else {
							frm.set_df_property("custom_fractional_leave_warning", "options", `<div> </div>`);
						}
					} 
				},
			});
		}
	},
	employee: function (frm) {
        frm.trigger("calculate_total_days");
    },
});
